import React, { useState, useEffect, useCallback } from 'react';
import { actionsAPI } from '../utils/api';

export default function PolicyPage() {
  const [whitelist, setWhitelist] = useState([]);
  const [blocked, setBlocked]     = useState([]);
  const [tab, setTab]             = useState('whitelist');
  const [loading, setLoading]     = useState(true);
  const [toast, setToast]         = useState('');

  const fetchAll = useCallback(async () => {
    setLoading(true);
    try {
      const [wl, bl] = await Promise.all([actionsAPI.getWhitelist(), actionsAPI.getBlocked()]);
      setWhitelist(wl.data.whitelist); setBlocked(bl.data.blocked_devices);
    } finally { setLoading(false); }
  }, []);

  useEffect(() => { fetchAll(); }, [fetchAll]);

  const remove = async (id) => { await actionsAPI.removeWhitelist(id); setToast('REMOVED FROM WHITELIST'); setTimeout(() => setToast(''), 3000); fetchAll(); };
  const unblock = async (id) => { await actionsAPI.unblockDevice(id); setToast('DEVICE UNBLOCKED'); setTimeout(() => setToast(''), 3000); fetchAll(); };

  const data = tab === 'whitelist' ? whitelist : blocked;

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '18px' }}>
      {toast && (
        <div className="animate-slide-in-right" style={{ position: 'fixed', top: '20px', right: '20px', zIndex: 200, background: 'rgba(0,255,136,0.1)', border: '1px solid rgba(0,255,136,0.4)', color: 'var(--accent-green)', fontFamily: "'Space Mono', monospace", fontSize: '10px', letterSpacing: '0.1em', padding: '10px 16px' }}>
          ✓ {toast}
        </div>
      )}

      <div>
        <div style={{ fontFamily: "'Space Mono', monospace", fontSize: '9px', color: 'var(--text-dim)', letterSpacing: '0.2em', marginBottom: '4px' }}>MODULE // PLY-001</div>
        <h1 style={{ fontSize: '22px', fontWeight: '700', color: 'var(--text-primary)' }}>Policy Engine</h1>
      </div>

      {/* Info banner */}
      <div style={{
        background: tab === 'whitelist' ? 'rgba(0,255,136,0.05)' : 'rgba(255,51,102,0.05)',
        border: `1px solid ${tab === 'whitelist' ? 'rgba(0,255,136,0.2)' : 'rgba(255,51,102,0.2)'}`,
        padding: '12px 16px', display: 'flex', gap: '10px', alignItems: 'flex-start',
      }}>
        <span style={{ color: tab === 'whitelist' ? 'var(--accent-green)' : 'var(--accent-red)', fontSize: '14px' }}>{tab === 'whitelist' ? '✓' : '⊘'}</span>
        <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '11px', color: 'var(--text-dim)', lineHeight: '1.5' }}>
          {tab === 'whitelist'
            ? 'Whitelisted devices are marked SAFE and will not generate threat alerts when connected.'
            : 'Blocked devices are marked CRITICAL when connected. All future connections trigger high-priority alerts.'}
        </div>
      </div>

      {/* Tabs */}
      <div style={{ display: 'flex', gap: '4px' }}>
        {[
          { key: 'whitelist', label: `WHITELIST [${whitelist.length}]`, color: 'var(--accent-green)' },
          { key: 'blocked',   label: `BLOCKED [${blocked.length}]`,     color: 'var(--accent-red)'   },
        ].map(t => (
          <button key={t.key} onClick={() => setTab(t.key)} style={{
            fontFamily: "'Space Mono', monospace", fontSize: '9px', letterSpacing: '0.12em',
            padding: '9px 18px', border: '1px solid', cursor: 'pointer', transition: 'all 0.15s',
            background: tab === t.key ? `${t.color}15` : 'transparent',
            borderColor: tab === t.key ? `${t.color}50` : 'var(--border-dim)',
            color: tab === t.key ? t.color : 'var(--text-dim)',
          }}>{t.label}</button>
        ))}
      </div>

      {/* Table */}
      <div style={{ background: 'var(--bg-panel)', border: '1px solid var(--border-dim)', position: 'relative', overflow: 'hidden' }}>
        <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: '1px', background: `linear-gradient(90deg, ${tab === 'whitelist' ? 'var(--accent-green)' : 'var(--accent-red)'}, transparent)` }} />
        {loading ? (
          <div style={{ textAlign: 'center', padding: '50px', color: 'var(--text-muted)', fontFamily: "'JetBrains Mono', monospace", fontSize: '11px' }}>LOADING POLICY RULES...</div>
        ) : !data.length ? (
          <div style={{ textAlign: 'center', padding: '50px', color: 'var(--text-muted)', fontFamily: "'JetBrains Mono', monospace", fontSize: '11px' }}>
            NO {tab.toUpperCase()} RULES — USE DEVICE MONITOR → ACTIONS TO ADD
          </div>
        ) : (
          <div style={{ overflowX: 'auto' }}>
            <table className="data-table">
              <thead>
                <tr>
                  {['Device Name', 'VID', 'PID', 'Serial', tab === 'whitelist' ? 'Notes' : 'Reason', 'Date', 'Action'].map(h => <th key={h}>{h}</th>)}
                </tr>
              </thead>
              <tbody>
                {data.map(d => (
                  <tr key={d.id}>
                    <td style={{ fontWeight: '600', color: 'var(--text-primary)' }}>{d.device_name || '—'}</td>
                    <td style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '11px', color: 'var(--accent-cyan)' }}>{d.vendor_id || '—'}</td>
                    <td style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '11px', color: 'var(--text-dim)' }}>{d.product_id || '—'}</td>
                    <td style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '10px', color: 'var(--text-muted)', maxWidth: '120px', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{d.serial_number || '—'}</td>
                    <td style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '10px', color: 'var(--text-dim)', maxWidth: '180px', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                      {(tab === 'whitelist' ? d.notes : d.reason) || '—'}
                    </td>
                    <td style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '9px', color: 'var(--text-muted)', whiteSpace: 'nowrap' }}>
                      {d.created_at ? new Date(d.created_at).toLocaleDateString() : '—'}
                    </td>
                    <td>
                      {tab === 'whitelist'
                        ? <button className="btn btn-danger"  style={{ padding: '4px 10px', fontSize: '9px' }} onClick={() => remove(d.id)}>REMOVE</button>
                        : <button className="btn btn-success" style={{ padding: '4px 10px', fontSize: '9px' }} onClick={() => unblock(d.id)}>UNBLOCK</button>
                      }
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}
